const EXCLUDED_STATUSES = new Set(['cancelled', 'refunded']);

function revenueByMonth(orders) {
  const buckets = new Map();

  for (const order of orders) {
    if (EXCLUDED_STATUSES.has(order.status)) continue;

    const d = new Date(order.placedAt);
    const month = `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, '0')}`;

    buckets.set(month, (buckets.get(month) ?? 0) + order.amountCents);
  }

  return Array.from(buckets.entries())
    .sort(([a], [b]) => (a < b ? -1 : 1))
    .map(([month, cents]) => ({ month, cents }));
}

